var overlayVideo={};
function overlayClose(item){
var iframes=item.querySelectorAll('.ba-item-custom-html iframe, .ba-item-video iframe, .ba-item-field-video iframe');
for (var i=0; i < iframes.length; i++){
let src=iframes[i].src,
videoId=iframes[i].id;
if (src&&src.indexOf('youtube.com') !==-1&&'pauseVideo' in overlayVideo[videoId]){
overlayVideo[videoId].pauseVideo();
} else if (src&&src.indexOf('vimeo.com') !==-1&&'pause' in overlayVideo[videoId]){
overlayVideo[videoId].pause();
} else if (src&&src.indexOf('youtube-nocookie.com') !==-1){
iframes[i].closest('.ba-video-wrapper').innerHTML=iframes[i].closest('.ba-video-wrapper').innerHTML;
}
}
iframes=item.querySelectorAll('.ba-item-video video, .ba-item-custom-html video, .ba-item-field-video video');
for (var i=0; i < iframes.length; i++){
let videoId=iframes[i].id;
overlayVideo[videoId].pause();
}
}
function overlayOpen(item){
if (item.querySelectorAll('.video-lazy-load-thumbnail')){
$g(item).find('.video-lazy-load-thumbnail').trigger('click');
}
var iframes=item.querySelectorAll('.ba-item-custom-html iframe, .ba-item-video iframe, .ba-item-field-video iframe'),
youtube=false,
vimeo=false,
id=+new Date();
for (var i=0; i < iframes.length; i++){
var src=iframes[i].src,
videoId;
if (src&&src.indexOf('youtube.com') !==-1){
if (!app.youtube){
youtube=true;
} else {
if (src.indexOf('enablejsapi=1')===-1){
if (src.indexOf('?')===-1){
src +='?';
} else {
src +='&'
}
src +='enablejsapi=1';
iframes[i].src=src;
}
if (!iframes[i].id){
iframes[i].id=id++;
}
videoId=iframes[i].id;
if (!overlayVideo[videoId] || !('playVideo' in overlayVideo[videoId])){
overlayVideo[videoId]=new YT.Player(videoId, {
events: {
onReady: function(event){
if (item.classList.contains('visible-section')){
overlayVideo[videoId].playVideo();
}
}
}
});
} else {
overlayVideo[videoId].playVideo();
}
}
} else if (src&&src.indexOf('vimeo.com') !==-1){
if (!app.vimeo){
vimeo=true;
} else {
if (!iframes[i].id){
iframes[i].id=id++;
}
videoId=iframes[i].id;
if (!overlayVideo[videoId] || !('play' in overlayVideo[videoId])){
src=src.split('/');
src=src.slice(-1);
src=src[0].split('?');
src=src[0];
var options={
id: src * 1,
loop: true,
};
overlayVideo[videoId]=new Vimeo.Player(videoId, options);
}
overlayVideo[videoId].play();
}
}
}
iframes=item.querySelectorAll('.ba-item-video video, .ba-item-custom-html video, .ba-item-field-video video');
for (var i=0; i < iframes.length; i++){
if (!iframes[i].id){
iframes[i].id=id++;
}
videoId=iframes[i].id;
if (!overlayVideo[videoId]){
overlayVideo[videoId]=iframes[i];
}
overlayVideo[videoId].play();
}
if (youtube || vimeo){
var object={
data : {}
};
if (youtube&&!vimeo){
object.data.type='youtube';
} else if (vimeo&&!youtube){
object.data.type='vimeo';
} else {
object.data.type='youtube+vimeo';
}
app.checkModule('loadVideoApi', object);
}
if (youtube){
overlayVideo.overlay=item;
} else if (vimeo){
overlayVideo.overlay=item;
}
return !youtube&&!vimeo;
}
